import React, { useState } from 'react';
import { loginAdmin } from '../../services/api';

const LoginPage = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await loginAdmin(username, password);
      if (response.data.access_token) {
        onLogin(response.data.access_token);
      }
    } catch (err) {
      setError('Invalid credentials! Use varshini / varshu');
    }
    setLoading(false);
  };

  return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)' }}>
      <div style={{ background: 'white', padding: '40px', borderRadius: '10px', boxShadow: '0 10px 40px rgba(0,0,0,0.2)', width: '400px' }}>
        <h1 style={{ textAlign: 'center', color: '#667eea' }}>🤖 AI Resume Screening</h1>
        <p style={{ textAlign: 'center', color: '#666', marginBottom: '30px' }}>Admin Login</p>
        {error && <div style={{ background: '#ffe0e0', color: '#d32f2f', padding: '10px', borderRadius: '5px', marginBottom: '15px' }}>{error}</div>}
        <form onSubmit={handleSubmit}>
          <input type="text" placeholder="Username" value={username} onChange={(e) => setUsername(e.target.value)} style={{ width: '100%', padding: '12px', margin: '10px 0', border: '1px solid #ddd', borderRadius: '5px', fontSize: '16px' }} required />
          <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} style={{ width: '100%', padding: '12px', margin: '10px 0', border: '1px solid #ddd', borderRadius: '5px', fontSize: '16px' }} required />
          <button type="submit" disabled={loading} style={{ width: '100%', padding: '12px', marginTop: '20px', background: '#667eea', color: 'white', border: 'none', borderRadius: '5px', fontSize: '16px', cursor: 'pointer' }}>{loading ? 'Logging in...' : 'Login'}</button>
        </form>
      </div>
    </div>
  );
};

export default LoginPage;
